<script>
let value=$state(""),query=$state(''),open=$state(false),message=$state('Ready'),page=$state(1);let range=['',''],start=$state(range[0]),end=$state(range[1]);const matches=x=>x.toLowerCase().includes(query.toLowerCase());function choose(x){value=x;query=x;open=false}function chooseKey(e,x){if(e.key==='Enter'||e.key===' '){e.preventDefault();choose(x)}}function key(e){if(e.key==='Escape')open=false;else if(e.key==='ArrowDown'||e.key==='ArrowUp'){e.preventDefault();open=true}}
</script>
<main class="family"><h1>DropdownMenu</h1><section><button class="menu-button" aria-haspopup="menu" aria-expanded={open} onclick={()=>open=!open} onkeydown={key}>Actions</button>{#if open}<div class="menu" role="menu"><button role="menuitem" tabindex="-1" onclick={()=>choose("Edit")}>Edit</button><button role="menuitem" tabindex="-1" onclick={()=>choose("Duplicate")}>Duplicate</button><button role="menuitem" tabindex="-1" onclick={()=>choose("Delete")}>Delete</button></div>{/if}</section></main>
